@import"https://fonts.googleapis.com/css2?family=Ma+Shan+Zheng&display=swap";@import"https://fontsapi.zeoseven.com/183/main/result.css";.step-indicator{display:flex;flex-direction:column;align-items:flex-start;justify-content:space-evenly;padding:1.8rem .8rem;height:100%;position:relative}@media(max-width: 519px){.step-indicator{flex-direction:row;align-items:center;justify-content:flex-start;gap:.3rem;min-width:max-content;height:100%;padding:0 .75rem}}@media(min-width: 520px)and (max-width: 767px){.step-indicator{padding:1.5rem .6rem}}.dot{display:flex;flex-direction:row;align-items:center;gap:.7rem;cursor:pointer;color:#686870;transition:color .24s ease;padding:.35rem 0;position:relative}@media(max-width: 519px){.dot{gap:0;padding:0;justify-content:center}}.dot .num{width:2.8rem;height:2.8rem;display:flex;align-items:center;justify-content:center;position:relative;background:#0c0c10;border:1px solid rgba(200,200,210,.18);border-radius:50%;box-shadow:inset 0 0 8px rgba(0,0,0,.7),0 1px 2px rgba(0,0,0,.5);transition:background .28s ease,border-color .28s ease,box-shadow .28s ease;flex-shrink:0}@media(max-width: 519px){.dot .num{width:2rem;height:2rem}}@media(min-width: 520px)and (max-width: 767px){.dot .num{width:2.4rem;height:2.4rem}}.dot .num .inner{font-family:"极影毁片辉宋 Bold","STKaiti","KaiTi","FangSong","Songti SC","SimSun",serif;font-size:1.1rem;font-weight:600;color:#9898a0}@media(max-width: 519px){.dot .num .inner{font-size:.85rem}}@media(min-width: 520px)and (max-width: 767px){.dot .num .inner{font-size:1rem}}.dot .num::before{content:"";position:absolute;inset:-5px;border-radius:50%;border:1px dashed rgba(216,56,56,.35);opacity:0;transition:opacity .3s ease}@media(max-width: 519px){.dot .num::before{inset:-3px}}.dot .title{font-family:"极影毁片辉宋 Bold","STKaiti","KaiTi","FangSong","Songti SC","SimSun",serif;font-size:.95rem;font-weight:600;letter-spacing:.1em;white-space:nowrap;color:#b8b8c0;transition:color .24s ease,text-shadow .24s ease}@media(max-width: 519px